head.script:
/* ★AIcraft guide★    
스크립트 수작업 유의사항
*/


scwin.delStr = /-/g;

scwin.onpageload = function() {
	scwin.OnInitScreen();
};

scwin.onpageunload = function() {}; //HYPEN 대체문자



//************************************* OnInitScreen EVENT *************************************

scwin.OnInitScreen = function() {
    pinpadInptYn.setValue(); //핀패드 조회 여부 초기화

    //본 팝업화면이 호출될 때 넘겨진 파라메터 중 고객번호(cuniqno), 고객식별자(custIdnfr) 둘 중에 null이 아닌 것이 하나라도 있으면 아래 거래처리를 한다.
    //(고객성명조회:KAA0490041)거래처리하여 고객성명을 조회한다.

    //2. 파라메터로 넘어온 값 중 영역구분(scopDstic)이 공백이면 'B'로 셋팅
    cuniqno.focus();
    if (scopDstic.getValue() == "") {
        scopDstic.setValue("B");
    }
    if (cuniqno.getValue() != "" || custIdnfr.getValue() != "") {
        scwin.fn_sendKey();
    }
};

scwin.fn_sendKey = async function() {
    cuniqno.setValue(cuniqno.getValue().replace(scwin.delStr, ""));
    totalLineCnt.setValue();
    dataBook.removeAll();
    $c.iz.tran.setTranID("KAA0490041");
    await $c.iz.tran.ASend();
};

//************************************* GRID EVENT *********************************************

scwin.dataBook_OnDClick = function(Arg1, Arg2, Arg3) {
    // 2차조회가능여부(n2ndInquryAbilYn) = '1' 일 경우 
    //    1. 입력항목의 고객번호(cuniqno), 고객식별자(custIdnfr), 고객관리번호(custMgtNo)를 Clear한다.
    //    2. 해당 Row의 고객식별자 -> 입력의 고객식별자(custIdnfr)
    //    3. 총라인수(totalLineCnt)를 Clear한다.

    // 2차조회가능여부(n2ndInquryAbilYn) = '1' 이 아닐 경우
    //   2.1 법인정보선택가능여부(coprInfoSelctAbilYn) = '1' 인 경우
    //       호출한 원 화면으로 선택된 그리드의 결과값을 전송하고 창을 닫는다.

    //		 법인정보선택가능여부(coprInfoSelctAbilYn) = '1' 이 아닌경우 경우  더블클릭해도 아무 반응이 없어야 함     



    if (Arg1 != 0) {
        var n2nB = dataBook.getCellData(Arg1, "n2ndInquryAbilYn"); //2차조회가능여부
        var GcorInfo = dataBook.getCellData(Arg1, "coprInfoSelctAbilYn"); //법인정보선택가능여부
        if (n2nB == 1) {
            cuniqno.setValue();
            custIdnfr.setValue();
            custMgtNo.setValue();
            totalLineCnt.setValue();
            custIdnfr.setValue(dataBook.getCellData(Arg1, "custIdnfr"));
            scwin.fn_sendKey();
        } else {
            if (GcorInfo == 1) {
                Link.cuniqno = dataBook.getCellData(Arg1, "cuniqno"); //고객번호
                Link.cuniqnoDstcd = dataBook.getCellData(Arg1, "cuniqnoDstcd"); //고객고유번호구분코드
                //alert(dataBook.GetCellDataSaveName(Arg1,"cuniqnoDstcd"),"구분코드");
                Link.dtalsCustPtrnClsfiDstcd = dataBook.getCellData(Arg1, "dtalsCustPtrnClsfiDstcd"); //세부고객유형분류구분코드
                Link.custIdnfr = dataBook.getCellData(Arg1, "custIdnfr"); //고객식별자
                Link.custMgtNo = dataBook.getCellData(Arg1, "custMgtNo"); //고객관리번호
                Link.custnm = dataBook.getCellData(Arg1, "custnm"); //고객명
                Link.custnm2 = dataBook.getCellData(Arg1, "custnm2"); //고객명2
                Link.cardCustnm = dataBook.getCellData(Arg1, "cardCustnm"); //카드고객명
                Link.rprsName = dataBook.getCellData(Arg1, "rprsName"); //대표자명
                Link.fnameErrDstcd = dataBook.getCellData(Arg1, "fnameErrDstcd"); //성명오류구분코드
                Link.fnameErrDsticName = dataBook.getCellData(Arg1, "fnameErrDsticName"); //성명오류구분명
                Link.outptLineCnt = outptLineCnt.getValue();
                if (dataBook.getCellData(Arg1, "dtalsCustPtrnClsfiDstcd") == '12' ||
                    dataBook.getCellData(Arg1, "dtalsCustPtrnClsfiDstcd") == '13') {
                    for (i = 1; i <= dataBook.getTotalRow(); i++) {
                        if (dataBook.getCellData(i, "dtalsCustPtrnClsfiDstcd") == '11' ||
                            dataBook.getCellData(i, "dtalsCustPtrnClsfiDstcd") == '14') {
                            //alert(dataBook.GetCellDataSaveName(i,"cuniqno"),"2");
                            Link.kecCuniqno = dataBook.getCellData(i, "cuniqno");
                            $c.iz.screen.screenClose();
                        }
                    }
                }
                Link.custEndStusDstcd = custEndStusDstcd.getValue();
                $c.iz.screen.screenClose();
            }
        }
    }
};



//************************************* BUTTON EVENT *******************************************

scwin.Button1_OnClick = function(e) {
    // 확인버튼
    //호출한 원 화면으로 선택된 그리드의 결과값을 전송하고 창을 닫는다.


    var row = dataBook.getFocusedRowIndex();
    Link.cuniqno = dataBook.getCellData(row, "cuniqno"); //고객번호
    Link.cuniqnoDstcd = dataBook.getCellData(row, "cuniqnoDstcd"); //고객고유번호구분코드
    //alert(dataBook.GetCellDataSaveName(row,"cuniqnoDstcd"),"구분코드");
    Link.dtalsCustPtrnClsfiDstcd = dataBook.getCellData(row, "dtalsCustPtrnClsfiDstcd"); //세부고객유형분류구분코드
    Link.custIdnfr = dataBook.getCellData(row, "custIdnfr"); //고객식별자
    Link.custMgtNo = dataBook.getCellData(row, "custMgtNo"); //고객관리번호
    Link.custnm = dataBook.getCellData(row, "custnm"); //고객명
    Link.custnm2 = dataBook.getCellData(row, "custnm2"); //고객명2
    Link.cardCustnm = dataBook.getCellData(row, "cardCustnm"); //카드고객명
    Link.rprsName = dataBook.getCellData(row, "rprsName"); //대표자명
    Link.fnameErrDstcd = dataBook.getCellData(row, "fnameErrDstcd"); //성명오류구분코드
    Link.fnameErrDsticName = dataBook.getCellData(row, "fnameErrDsticName"); //성명오류구분명

    if (dataBook.getCellData(row, "dtalsCustPtrnClsfiDstcd") == '12' ||
        dataBook.getCellData(row, "dtalsCustPtrnClsfiDstcd") == '13') {
        for (i = 1; i <= dataBook.getTotalRow(); i++) {
            if (dataBook.getCellData(i, "dtalsCustPtrnClsfiDstcd") == '11' ||
                dataBook.getCellData(i, "dtalsCustPtrnClsfiDstcd") == '14') {
                //alert(dataBook.GetCellDataSaveName(i,"cuniqno"),"2");
                Link.kecCuniqno = dataBook.getCellData(i, "cuniqno");
                $c.iz.screen.screenClose();
            }
        }
    }
    Link.custEndStusDstcd = custEndStusDstcd.getValue();
    $c.iz.screen.screenClose();
};


scwin.btnClear_OnClick = function(e) {
    //사업장주소초기화
    //사업장우편번호, 사업장우편번호주소, 사업장상세주소를 Clear한다									

    cuniqno.setValue();
    custIdnfr.setValue();
    custMgtNo.setValue();
    cuniqno.focus();
};




//************************************* COMMON BUTTON EVENT ************************************

scwin.OnSendKey = function() {
    //1. 고객번호(cuniqno), 고객식별자(custIdnfr) 둘 중에 null이 아닌 것이 하나라도 있으면 아래 거래처리를 한다.
    //2. 고객번호(cuniqno), 고객식별자(custIdnfr) 둘 다 null일 경우 "고객번호 또는 고객식별자를 입력해 주십시오." 메시지 처리

    //1. (고객성명조회:KAA0490041)거래처리하여 고객성명을 조회한다.


    if (cuniqno.getValue() == "" && custIdnfr.getValue() == "") {
        $c.iz.data.message("고객번호 또는 고객정보번호를 입력해 주십시오.");
        cuniqno.focus();
    } else {
        scwin.fn_sendKey();
    }
};



scwin.Button2_OnClick = function(e) {
    //여기에 구현코드를 삽입하세요.
    $c.iz.screen.screenClose();
};

scwin.OnEndTran = function() {
    var strDtalsCustPtrnClsfiDstcd = "";
    var countDtalsCustPtrnClsfiDstcd = "";
    var strCuniqno = "";
    var strCuniqno_2 = "";
    pinpadInptYn.setValue(); //핀패드 조회 여부 초기화	

    //여기에 구현코드를 삽입하세요.
    if ($c.iz._tran.tranId == "KAA0490041") {
        if ($c.iz._tran.bError == false) {
            if (ppsnBzmanJntRpsntYn.getValue() == "1") {
                $c.iz.data.message("해당 사업자번호의 개인사업자가 여러 건 존재합니다.");
                Link.cuniqno = cuniqno.getValue(); // 사업자번호
                $c.iz.screen.popup("KAA04905001", "DATALINK");
                var tempValue1 = Link.custIdnfr;
                var tempValue2 = Link.custMgtNo;
                var tempValue3 = Link.rprsCuniqno;
                if (tempValue1 != "" && typeof(tempValue1) != "undefined") {
                    // 고유정보번호
                    if (tempValue3 != "") {
                        custIdnfr.setValue(tempValue1);
                    } else {
                        custIdnfr.setValue(tempValue1);
                        custMgtNo.setValue(tempValue2);
                    }
                    // 고객구분
                    cuniqno.setValue("");
                    scwin.OnSendKey();
                }
            }

            //거래종료상태구분
            if (custEndStusDstcd.getValue() == "1") {
                custEndStusText.show('');
            } else {
                custEndStusText.hide();
            }
            for (i = 1; i <= dataBook.getTotalRow(); i++) {
                strDtalsCustPtrnClsfiDstcd = dataBook.getCellData(i, "dtalsCustPtrnClsfiDstcd"); // 세부고객유형구분
                strCuniqno = dataBook.getCellData(i, "cuniqno"); // 개인고객번호
                strCuniqno_2 = strCuniqno.substr(0, 7);

                //			alert(strCuniqno,"고객번호");
                //			alert(strCuniqno_2,"본인확인번호");

                if (strDtalsCustPtrnClsfiDstcd == "12") {
                    //	개인사업자
                    dataBook.setCellData(i, "cuniqno_2", strCuniqno);
                } else {
                    dataBook.setCellData(i, "cuniqno_2", strCuniqno_2);
                }
            }
        } else {
            // KB-PIN 중복 
            if ($c.iz._tran.treatCd == "UKAA1977") {
                var tmp = $c.iz._tran.errMsg; //사용자 맞춤 메세지 
                var arrValue1 = tmp.split("(");
                if (arrValue1.length > 2) {
                    var tmp_custIdnfr1 = arrValue1[1].substr(0, 10);
                    var tmp_custIdnfr2 = arrValue1[2].substr(0, 10);
                    Link.custIdnfr1 = tmp_custIdnfr1;
                    Link.custIdnfr2 = tmp_custIdnfr2;
                    Link.cuniqno = cuniqno.getValue();
                    $c.iz.screen.popup("KAA0490000P", "DATALINK");
                    // 재조회 
                    var tmp_custIdnfr = Link.pick_custIdnfr;
                    if (typeof(tmp_custIdnfr) != "undefined" && tmp_custIdnfr != '') {
                        custIdnfr.setValue(tmp_custIdnfr);
                        cuniqno.setValue("");
                        scwin.OnSendKey();
                    }
                }
            }
        }
    }
};

scwin.cuniqno_OnKeyTyped = function(Key) {
    //	var strSerchNo = cuniqno.Data;
    //	var strTemp = strSerchNo.replace("-", "");
    //	while(strSerchNo != strTemp)
    //	{
    //		strSerchNo = strTemp;
    //		strTemp = strSerchNo.replace("-", "");
    //	}
    //	cuniqno.Data = strTemp;
    custIdnfr.setValue();
};

scwin.custIdnfr_OnKeyTyped = function(Key) {
    cuniqno.setValue();
};
