scwin.btnPinPad_OnClick = function(e) {
    //* 주민번호 핀패드 입력 : 2015.01.05 
    $c.iz.data.message("고객님께 Pin-Pad로 주민번호 요청중입니다. " + "(취소하려면 Shift + ESC 키를 눌러주세요)");
    var pinCuniqno = ReadPinPadPasswordSound(39, 13, 13, 1);
    SendResultPinPadPasswordClose();
    $c.iz.data.message("");
    if ($c.iz.data.trim(pinCuniqno) != '') {
        cuniqno.setValue(pinCuniqno);
        custIdnfr.setValue();
        custMgtNo.setValue();
        pinpadInptYn.setValue('1'); //핀패드 조회 여부 SETTING

        scwin.OnSendKey();
    }
};
